module mux3to1(
    enable,
    clk,
    sel,
    in0,
    in1,
    in2,
    out);

// Inputs
input enable;
input clk;
input [2:0] sel;
input in0;
input in1;
input in2;

// Outputs
output out;

reg out;

always @ (posedge clk) begin
    if (enable) begin
        out <= 1'b0;
    end else begin
        case (sel)
            3'b000: out <= in0;
            3'b001: out <= in1;
            3'b010: out <= in2;
            default: out <= 1'b0;
        endcase
    end
end

endmodule
